function getSystemDefaultLanguage() {
  if (typeof navigator !== 'undefined') {
    const locale = navigator.language || navigator.userLanguage || "en";
    const code = locale.toLowerCase();
    if (code.startsWith("uk") || code.startsWith("ua")) {
      return "ua";
    }
  }
  return "en";
}

