// Translation Resolver Helper
function t(obj) {
  if (obj && typeof obj === 'object') {
    return obj[state.lang] || obj['en'] || "";
  }
  return obj || "";
}

// Localize page structure
function translateUI() {
  document.querySelectorAll("[data-i18n]").forEach(el => {
    const key = el.getAttribute("data-i18n");
    const localizedText = LOCALIZATION[state.lang][key];
    if (localizedText) {
      // Preserve inner html tags (like icon spans inside buttons)
      if (el.querySelector("span") || el.innerHTML.includes("<span")) {
        // Just replace the text content part or target inner span
        const innerSpan = el.querySelector("[data-i18n]");
        if (innerSpan) {
          innerSpan.innerText = localizedText;
        } else {
          // Fallback, replace text nodes
          el.childNodes.forEach(node => {
            if (node.nodeType === Node.TEXT_NODE && node.nodeValue.trim() !== "") {
              node.nodeValue = localizedText;
            }
          });
        }
      } else {
        el.innerText = localizedText;
      }
    }
  });
  
  // Update toggle button text
  const langBtn = document.getElementById("btn-lang");
  if (langBtn) {
    langBtn.innerText = `🌐 ${state.lang === 'en' ? 'En' : 'Ua'}`;
  }
  const modalLangBtn = document.getElementById("btn-modal-lang");
  if (modalLangBtn) {
    modalLangBtn.innerText = `🌐 ${state.lang === 'en' ? 'En' : 'Ua'}`;
  }
}

function applyTheme() {
  if (state.theme === "light") {
    document.documentElement.classList.add("theme-light");
  } else {
    document.documentElement.classList.remove("theme-light");
  }
}

// ==========================================
// CORE GAME MECHANICS & CALCULATIONS
// ==========================================

function getXPNeededForLevel(level) {
  return Math.round(100 * Math.pow(1.28, level - 1));
}

function getStatXPNeededForLevel(level) {
  return Math.round(100 * Math.pow(1.24, level - 1));
}

// Characteristics Multipliers
function getMaliceModifier() {
  const val = (state.statLevels && typeof state.statLevels.malice === 'number' && !isNaN(state.statLevels.malice)) ? state.statLevels.malice : 1;
  return 1 + (val * 0.01);
}

function getBrutalityModifier() {
  const val = (state.statLevels && typeof state.statLevels.brutality === 'number' && !isNaN(state.statLevels.brutality)) ? state.statLevels.brutality : 1;
  return 1 / (1 + (val * 0.005));
}

// Multipliers
function getGuileGoldModifier() {
  const val = (state.statLevels && typeof state.statLevels.guile === 'number' && !isNaN(state.statLevels.guile)) ? state.statLevels.guile : 1;
  return 1 + (val * 0.015);
}

function getGuileDoubleChance() {
  const val = (state.statLevels && typeof state.statLevels.guile === 'number' && !isNaN(state.statLevels.guile)) ? state.statLevels.guile : 1;
  return val * 0.005;
}

function getDevotionModifier() {
  const val = (state.statLevels && typeof state.statLevels.devotion === 'number' && !isNaN(state.statLevels.devotion)) ? state.statLevels.devotion : 1;
  const reduction = val * 0.004;
  return Math.max(0.6, 1 - reduction);
}

function getCorruptionXPModifier() {
  const val = (state.statLevels && typeof state.statLevels.corruption === 'number' && !isNaN(state.statLevels.corruption)) ? state.statLevels.corruption : 1;
  return 1 + (val * 0.008);
}

function getWillpowerFailMitigation() {
  const val = (state.statLevels && typeof state.statLevels.willpower === 'number' && !isNaN(state.statLevels.willpower)) ? state.statLevels.willpower : 1;
  return val * 0.015;
}

function getWillpowerMinionSlots() {
  const val = (state.statLevels && typeof state.statLevels.willpower === 'number' && !isNaN(state.statLevels.willpower)) ? state.statLevels.willpower : 1;
  return 1 + Math.floor(val / 20);
}

function getInfernalSpeedModifier() {
  const val = (state.statLevels && typeof state.statLevels.infernal === 'number' && !isNaN(state.statLevels.infernal)) ? state.statLevels.infernal : 1;
  return 1 / (1 + (val * 0.01));
}

function getInfernalFuelModifier() {
  const val = (state.statLevels && typeof state.statLevels.infernal === 'number' && !isNaN(state.statLevels.infernal)) ? state.statLevels.infernal : 1;
  const reduction = val * 0.01;
  return Math.max(0.2, 1 - reduction);
}

function getResilienceLossMitigation() {
  const val = (state.statLevels && typeof state.statLevels.resilience === 'number' && !isNaN(state.statLevels.resilience)) ? state.statLevels.resilience : 1;
  let reduction = val * 0.02;
  if (hasMinionEquipped("gargoyle")) {
    reduction += 0.10; // +10% resilience loss reduction from Gargoyle
  }
  return Math.max(0.1, 1 - reduction);
}

function calculateActivityYield(activity, resourceKey, amount) {
  let finalAmt = amount;
  
  // Flat modifiers first
  if (resourceKey === "sulfur" && hasMinionEquipped("imp")) {
    finalAmt += 1;
  }
  
  // Multipliers
  if (RESOURCES[resourceKey].category === "ethereal") {
    finalAmt = finalAmt * getMaliceModifier();
  } else if (RESOURCES[resourceKey].category === "mortal") {
    finalAmt = finalAmt * getGuileGoldModifier();
  } else if (RESOURCES[resourceKey].category === "crafted" && resourceKey === "unholy_elixir") {
    finalAmt = finalAmt * getSorceryElixirModifier();
  } else if (RESOURCES[resourceKey].category === "geological") {
    finalAmt = finalAmt * getAvariceLootModifier();
  }
  
  // Upgrade multipliers
  if (state.upgrades) {
    const lvlAlchemy = getUpgradeLevel("unholy_cauldron");
    if (activity.category === "alchemy" && lvlAlchemy > 0) finalAmt *= UPGRADES.unholy_cauldron.getEffectMultiplier(lvlAlchemy);
    
    const lvlTorture = getUpgradeLevel("scythe_of_screams");
    if (activity.category === "torture" && lvlTorture > 0) finalAmt *= UPGRADES.scythe_of_screams.getEffectMultiplier(lvlTorture);
    
    const lvlNecro = getUpgradeLevel("necromancers_staff");
    if (activity.category === "necromancy" && lvlNecro > 0) finalAmt *= UPGRADES.necromancers_staff.getEffectMultiplier(lvlNecro);
    
    const lvlAgri = getUpgradeLevel("harvest_sickle");
    if (activity.category === "agriculture" && lvlAgri > 0) finalAmt *= UPGRADES.harvest_sickle.getEffectMultiplier(lvlAgri);
    
    const lvlVoid = getUpgradeLevel("void_excavator");
    if (activity.category === "void" && lvlVoid > 0) finalAmt *= UPGRADES.void_excavator.getEffectMultiplier(lvlVoid);
    
    const lvlPlague = getUpgradeLevel("plague_nest");
    if (activity.category === "plague" && lvlPlague > 0) finalAmt *= UPGRADES.plague_nest.getEffectMultiplier(lvlPlague);
  }
  
    if (state.activeBoosterId && !state.boosterIsPaused) {
    if (state.activeBoosterId === "hellfire_surge" && resourceKey !== "gold" && RESOURCES[resourceKey].category !== "ethereal" && RESOURCES[resourceKey].category !== "companion") {
      finalAmt *= 1.20;
    } else if (state.activeBoosterId === "agony_catalyst" && RESOURCES[resourceKey].category === "ethereal") {
      finalAmt *= 1.30;
    } else if (state.activeBoosterId === "sanguine_blessing" && (resourceKey === "blood_essence" || resourceKey === "lapis_sanguine")) {
      finalAmt *= 1.25;
    } else if (state.activeBoosterId === "chaos_singularity_boost" && resourceKey === "chaos_sparks") {
      finalAmt *= 1.50;
    } else if (state.activeBoosterId === "monarch_dominion" && resourceKey === "gold") {
      finalAmt *= 1.15;
    } else if (state.activeBoosterId === "sins_overdrive" && activity.category === "sins") {
      finalAmt *= 2.0;
    }
  }
  
  return Math.round(finalAmt);
}

function getSorcerySpeedModifier() {
  const val = (state.statLevels && typeof state.statLevels.sorcery === 'number' && !isNaN(state.statLevels.sorcery)) ? state.statLevels.sorcery : 1;
  return 1 / (1 + (val * 0.01));
}

function getSorceryElixirModifier() {
  const val = (state.statLevels && typeof state.statLevels.sorcery === 'number' && !isNaN(state.statLevels.sorcery)) ? state.statLevels.sorcery : 1;
  return 1 + (val * 0.015);
}

function getAvariceLootModifier() {
  const val = (state.statLevels && typeof state.statLevels.avarice === 'number' && !isNaN(state.statLevels.avarice)) ? state.statLevels.avarice : 1;
  return 1 + (val * 0.015);
}

function calculateDuration(activity) {
  let mult = 1;
  const physicalCats = ["extraction", "forge", "agriculture", "void", "plague"];
  const magicCats = ["veil", "rites", "alchemy", "necromancy", "blood", "chaos", "astral", "sins"];
  const mentalCats = ["conquest", "torture"];
  
  if (physicalCats.includes(activity.category)) {
    mult *= getBrutalityModifier();
  } else if (magicCats.includes(activity.category)) {
    mult *= getSorcerySpeedModifier();
  } else if (mentalCats.includes(activity.category)) {
    const val = (state.statLevels && typeof state.statLevels.willpower === 'number' && !isNaN(state.statLevels.willpower)) ? state.statLevels.willpower : 1;
    mult *= 1 / (1 + (val * 0.005));
  }
  
  if (activity.category === "extraction") {
    if (state.equipment.tool === "brimstone_brand") mult *= 0.90;
    const lvlSledge = getUpgradeLevel("brimstone_sledge");
    if (lvlSledge > 0) mult *= UPGRADES.brimstone_sledge.getEffectMultiplier(lvlSledge);
  } else if (activity.category === "veil") {
    if (state.equipment.accessory === "obsidian_sigil") mult *= 0.90;
  } else if (activity.category === "forge") {
    if (state.equipment.tool === "brimstone_brand") mult *= 0.90;
    mult *= getInfernalSpeedModifier();
    const lvlFurnace = getUpgradeLevel("blood_furnace");
    if (lvlFurnace > 0) mult *= UPGRADES.blood_furnace.getEffectMultiplier(lvlFurnace);
  } else if (activity.category === "chaos") {
    const lvlChaos = getUpgradeLevel("chaos_stabilizer");
    if (lvlChaos > 0) mult *= UPGRADES.chaos_stabilizer.getEffectMultiplier(lvlChaos);
  }
  
  const base = typeof activity.baseTime === 'number' ? activity.baseTime : 2000;
    if (state.activeBoosterId && !state.boosterIsPaused) {
    if (state.activeBoosterId === "brimstone_haste") {
      mult *= 0.85;
    } else if (state.activeBoosterId === "void_alacrity") {
      mult *= 0.70;
    } else if (state.activeBoosterId === "plague_catalyst" && activity.category === "plague") {
      mult *= 0.80;
    } else if (state.activeBoosterId === "demonic_iron_tempering" && activity.category === "forge") {
      mult *= 0.85;
    } else if (state.activeBoosterId === "bloodlust_rage" && activity.category === "conquest") {
      mult *= 0.85;
    }
  }
  
  return Math.max(100, Math.round(base * (isNaN(mult) ? 1 : mult)));
}

function canAfford(activity) {
  if (!activity.cost) return true;
  
  let scale = 1;
  if (activity.category === "rites") scale = getDevotionModifier();
  if (activity.category === "forge") scale = getInfernalFuelModifier();
  
    if (state.activeBoosterId === "sins_overdrive" && activity.category === "sins") {
    if ((state.resources.gold || 0) < 5) return false;
  }
  
  for (const [key, amount] of Object.entries(activity.cost)) {
    let cost = amount;
    if (activity.category === "rites" && RESOURCES[key].category === "ethereal") {
      cost = Math.max(1, Math.round(amount * scale));
    }
    if (activity.category === "forge" && (key === "hellfire" || key === "sulfur")) {
      cost = Math.max(1, Math.round(amount * scale));
    }
    if ((state.resources[key] || 0) < cost) return false;
  }
  return true;
}

function deductCost(activity) {
  if (!activity.cost) return;
  
  let scale = 1;
  if (activity.category === "rites") scale = getDevotionModifier();
  if (activity.category === "forge") scale = getInfernalFuelModifier();
  
    if (state.activeBoosterId === "sins_overdrive" && activity.category === "sins") {
    state.resources.gold = Math.max(0, (state.resources.gold || 0) - 5);
    spawnGainIndicator("-5 💰", "💰");
  }
  
  for (const [key, amount] of Object.entries(activity.cost)) {
    let cost = amount;
    if (activity.category === "rites" && RESOURCES[key].category === "ethereal") {
      cost = Math.max(1, Math.round(amount * scale));
    }
    if (activity.category === "forge" && (key === "hellfire" || key === "sulfur")) {
      cost = Math.max(1, Math.round(amount * scale));
    }
    state.resources[key] -= cost;
  }
}

// ==========================================
// EXPERIENCE LOGIC LOOPS
// ==========================================

function addSkillXP(category, amount) {
  let scale = 1;
  const lvlCrown = getUpgradeLevel("crown_of_the_pit");
  if (lvlCrown > 0) {
    scale *= UPGRADES.crown_of_the_pit.getEffectMultiplier(lvlCrown);
  }
    if (state.activeBoosterId && !state.boosterIsPaused) {
    if (state.activeBoosterId === "elixir_infusion") scale *= 1.25;
  }
  
  const xpGained = Math.round(amount * getCorruptionXPModifier() * scale);
  state.skillXP[category] += xpGained;
  
  let leveledUp = false;
  while (state.skillXP[category] >= getXPNeededForLevel(state.skillLevels[category])) {
    const needed = getXPNeededForLevel(state.skillLevels[category]);
    state.skillLevels[category]++;
    state.skillXP[category] -= needed;
    leveledUp = true;
    
    if (!isSimulatingOffline) {
      const localizedSkill = LOCALIZATION[state.lang][`path_${category}`] || category;
      const msg = state.lang === "en" ? 
        `🌋 Skill Level Up! Your ${localizedSkill} skill is now Level ${state.skillLevels[category]}!` :
        `🌋 Рівень навички підвищено! Ваша навичка ${localizedSkill} тепер на рівні ${state.skillLevels[category]}!`;
      showNotification(msg);
    }
  }
  
  if (leveledUp && !isSimulatingOffline) {
    renderWorkspace();
  }
}

function addStatXP(statKey, amount) {
  let scale = 1;
  if (statKey === "brutality" && hasMinionEquipped("hellhound")) {
    scale += 0.05;
  }
  const lvlCrown = getUpgradeLevel("crown_of_the_pit");
  if (lvlCrown > 0) {
    scale *= UPGRADES.crown_of_the_pit.getEffectMultiplier(lvlCrown);
  }
  
    if (state.activeBoosterId && !state.boosterIsPaused) {
    if (state.activeBoosterId === "elixir_infusion") scale *= 1.25;
    if (state.activeBoosterId === "astral_focus") scale *= 1.50;
  }
  
  const xpGained = Math.round(amount * getCorruptionXPModifier() * scale);
  state.statXP[statKey] += xpGained;
  
  let leveledUp = false;
  while (state.statXP[statKey] >= getStatXPNeededForLevel(state.statLevels[statKey])) {
    const needed = getStatXPNeededForLevel(state.statLevels[statKey]);
    state.statLevels[statKey]++;
    state.statXP[statKey] -= needed;
    leveledUp = true;
    
    if (!isSimulatingOffline) {
      const msg = state.lang === "en" ? 
        `🔥 Attribute Grew! ${t(CHARACTERISTICS[statKey].name)} has ascended to Level ${state.statLevels[statKey]}!` :
        `🔥 Атрибут зріс! ${t(CHARACTERISTICS[statKey].name)} тепер на рівні ${state.statLevels[statKey]}!`;
      showNotification(msg);
    }
  }
  
  if (leveledUp && !isSimulatingOffline) {
    renderStatsPanel();
  }
}

function hasMinionEquipped(minionKey) {
  return state.minions.includes(minionKey);
}

function payoutRewards(activity) {
  const isDouble = Math.random() < getGuileDoubleChance();
  let multiplier = isDouble ? 2 : 1;
  
  for (const [key, amount] of Object.entries(activity.yield)) {
    let finalAmount = calculateActivityYield(activity, key, amount);
    if (amount < 1 && finalAmount < 1) {
      const roll = Math.random();
      if (roll > finalAmount) continue;
      finalAmount = 1;
    }
    
    finalAmount *= multiplier;
    state.resources[key] += finalAmount;
    
    // Spawn floating gain indicators on screen
    spawnGainIndicator(`+${finalAmount} ${t(RESOURCES[key].name)}`, RESOURCES[key].icon);
    
    if (isDouble) {
      const msg = state.lang === "en" ? `✦ Cunning Strike! Doubled yields on ${t(RESOURCES[key].name)}!` : `✦ Підступний удар! Подвоєно збір ${t(RESOURCES[key].name)}!`;
      showNotification(msg);
    }
  }

  const baseSkillXP = Math.round(activity.baseTime / 100);
  addSkillXP(activity.category, baseSkillXP);
  activity.statsTrained.forEach(stat => {
    addStatXP(stat.key, stat.xp);
  });
  
  if (!isSimulatingOffline) {
    checkMilestoneProgress();
  }
}

function executeRaid(activity) {
  const baseFail = activity.failChance || 0;
  const mitigation = getWillpowerFailMitigation();
    let failChanceMod = 0;
  let lossMod = 1;
  if (state.activeBoosterId && !state.boosterIsPaused) {
    if (state.activeBoosterId === "bloodlust_rage") failChanceMod += 10;
    if (state.activeBoosterId === "imperial_sovereignty") failChanceMod += 20;
    if (state.activeBoosterId === "bone_wall_fortitude") lossMod *= 0.5;
  }
  const finalFailChance = Math.max(0, baseFail * (1 - mitigation) - failChanceMod);
  
  
  const roll = Math.random() * 100;
  
  if (roll < finalFailChance) {
    let lossMsg = state.lang === "en" ? "Conquest Failed! Your dark forces were repelled." : "Завоювання провалилося! Ваші темні сили були відкинуті.";
    const lossMultiplier = getResilienceLossMitigation();
    
    if (activity.id === "subjugate_city" && Math.random() < 0.5 * lossMultiplier * lossMod) {
      if (state.resources.hellhound > 0) {
        state.resources.hellhound--;
        lossMsg += state.lang === "en" ? " A backup Hellhound was lost in the chaos." : " Резервний Гончак загинув у хаосі.";
      }
    }
    showNotification(`☠ ${lossMsg}`, "danger");
  } else {
    if (activity.id === "raid_hamlets") state.completedRaidsCount.hamlet++;
    if (activity.id === "plunder_cathedral") state.completedRaidsCount.cathedral++;
    if (activity.id === "subjugate_city") state.completedRaidsCount.city++;
    
    payoutRewards(activity);
    const msg = state.lang === "en" ? `⚔ Conquest Successful! Plundered mortal lands.` : `⚔ Завоювання успішне! Землі смертних розграбовано.`;
    showNotification(msg);
  }
}

