// ==========================================
// SYSTEM INITIALIZATION AND LOOPS
// ==========================================

function showNotification(msg, type = "success") {
  if (isSimulatingOffline) return;
  const existing = document.querySelector(".game-notification");
  if (existing) existing.remove();
  
  const notify = document.createElement("div");
  notify.className = `game-notification show`;
  if (type === "danger") notify.style.borderColor = "#ff3e3e";
  
  const icon = type === "danger" ? "☠" : "✦";
  notify.innerHTML = `
    <span class="notification-icon" style="color:${type === 'danger' ? '#ff3e3e' : '#ffd23f'}">${icon}</span>
    <span class="notification-message">${msg}</span>
  `;
  document.body.appendChild(notify);
  
  setTimeout(() => {
    notify.classList.remove("show");
    setTimeout(() => notify.remove(), 300);
  }, 4000);
}

function spawnGainIndicator(text, icon) {
  if (isSimulatingOffline) return;
  const container = document.getElementById("floating-gain-container");
  if (!container) return;
  
  const indicator = document.createElement("div");
  indicator.className = "floating-gain-item";
  indicator.innerHTML = `<span class="gain-icon">${icon}</span> <span class="gain-text">${text}</span>`;
  container.appendChild(indicator);
  
  setTimeout(() => {
    indicator.classList.add("fade-up");
  }, 20);
  
  setTimeout(() => {
    indicator.style.opacity = "0";
    setTimeout(() => {
      indicator.remove();
    }, 400);
  }, 1200);
}

function tick() {
  if (state.isPaused) {
    state.lastSaveTime = Date.now();
    lastTickTime = Date.now(); // reset tick timer when paused
    return;
  }
  
  const now = Date.now();
  const dt = now - lastTickTime;
  lastTickTime = now;
  // Update active booster countdown (dt is in milliseconds)
  if (state.activeBoosterId && !state.boosterIsPaused) {
    state.boosterTimeRemaining -= dt;
    if (state.boosterTimeRemaining <= 0) {
      const expiredId = state.activeBoosterId;
      state.activeBoosterId = null;
      state.activeBoosterType = null;
      state.boosterTimeRemaining = 0;
      
      // Auto-renew if autoConsume is checked and we own more of the same booster
      if (state.boosterAutoConsume && (state.boostersOwned[expiredId] || 0) > 0) {
        state.boostersOwned[expiredId]--;
        state.activeBoosterId = expiredId;
        state.activeBoosterType = BOOSTERS[expiredId].type;
        state.boosterTimeRemaining = BOOSTERS[expiredId].duration * 1000;
        if (!isSimulatingOffline) {
          showNotification(state.lang === "en" ? `Booster auto-renewed: ${t(BOOSTERS[expiredId].name)}!` : `Бустер автоматично активовано: ${t(BOOSTERS[expiredId].name)}!`);
        }
      } else {
        if (!isSimulatingOffline) {
          showNotification(state.lang === "en" ? "Booster effect expired." : "Дія бустера закінчилася.", "warning");
        }
      }
      
      // Re-render boosters view if active
      const activeTabBtn = document.querySelector(".nav-btn.active");
      const currentTab = activeTabBtn ? activeTabBtn.getAttribute("data-tab") : null;
      if (currentTab === "boosters") {
        renderBoosters();
      }
    }
  }
  
    
  if (state.activeActivity) {
    const act = ACTIVITIES.find(a => a.id === state.activeActivity);
    if (!act) {
      state.activeActivity = null;
      return;
    }
    
    const duration = calculateDuration(act);
    state.activeProgress += dt;
    
    const progressBar = document.getElementById(`progress-${act.id}`);
    if (progressBar) {
      const pct = Math.min(100, (state.activeProgress / duration) * 100);
      progressBar.style.width = `${pct}%`;
    }
    
    if (state.activeProgress >= duration) {
      state.activeProgress = 0;
      
      if (act.category === "conquest") {
        executeRaid(act);
        if (!canAfford(act)) {
          state.activeActivity = null;
          const msg = state.lang === "en" ? "Focus stopped: Ran out of resources to sustain conquest." : "Фокус зупинено: Недостатньо ресурсів для завоювання.";
          showNotification(msg, "danger");
          renderTopBar();
          renderWorkspace();
        } else {
          deductCost(act);
        }
      } else {
        if (canAfford(act)) {
          deductCost(act);
          payoutRewards(act);
          if (!canAfford(act)) {
            state.activeActivity = null;
            const msg = state.lang === "en" ? "Focus stopped: Ran out of resources." : "Фокус зупинено: Закінчилися ресурси.";
            showNotification(msg, "danger");
            renderTopBar();
            renderWorkspace();
          }
        } else {
          state.activeActivity = null;
          const msg = state.lang === "en" ? "Focus stopped: Ran out of resources." : "Фокус зупинено: Закінчилися ресурси.";
          showNotification(msg, "danger");
          renderTopBar();
          renderWorkspace();
        }
      }
      
      renderTopBar();
      renderStatsPanel();
      updateActiveSkillHeaderProgress(act.category); // Update active skill progress in real time
      const activeTabBtn = document.querySelector(".nav-btn.active");
      const currentTab = activeTabBtn ? activeTabBtn.getAttribute("data-tab") : null;
      if (currentTab === "inventory") {
        renderInventory();
      } else {
        renderWorkspace();
      }
    }
  }
}

